var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"CAKE_CHOCOLAT_NPC_BROTHER","text":{"KOREA":"오호호호~! 어떠신가, 벽 너머의 여러분!","JPN":"オホホホ～！　いかがでしょう、壁の向こうの皆さん！","ENG":"Hohoho! What do you think, people from beyond the screen?","TWN":"喔呵呵呵～！怎麼樣，另一邊的各位！"},"stage":{"bg":"CHOCOLAT_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CAKE_CHOCOLAT_NPC_BROTHER","text":{"KOREA":"다들 이 몸이 준비한 특별한 크리스마스 선물은 마음에 드시나?","JPN":"この私が用意した特別なクリスマスプレゼントは気に入ったかね？","ENG":"Do you like this special Christmas gift I have prepared for you?","TWN":"大家喜歡我準備的特別聖誕禮物嗎？"},"stage":{"bg":"CHOCOLAT_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CAKE_CHOCOLAT_NPC_BROTHER","text":{"KOREA":"15세 이용가에서 이 정도 서비스면, 나름 잊지 못할 추억이 되었겠지?","JPN":"R15+でこのサービスなら、それなりに忘れられない思い出になっただろう？","ENG":"I'm sure this will be an unforgettable gift in a game of this age rating, no?","TWN":"以輔導級來說，這樣的場面也算是相當難忘的回憶了吧？"},"stage":{"bg":"CHOCOLAT_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BIBLIDES_XMAS_NULL_NULL","text":{"KOREA":"큿…! 안경… 안경만 있었으면 이런 침식체……!","JPN":"くっ……！　眼鏡……眼鏡さえあったらこんな侵食体なんか……！","ENG":"Kgh...! If only... If only I had my glasses, then this C.O. would be...!","TWN":"可惡……！如果有眼鏡的話，這種侵蝕體……！"},"stage":{"bg":"CHOCOLAT_01","slots":{"L":null,"C":null,"R":{"char_id":"BIBLIDES_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"BIBLIDES_XMAS_NULL_NULL","text":{"KOREA":"모두 앞에서 이런 꼴을 보이게 하다니… 어, 어쩜 이렇게 불경할 수가……!","JPN":"みんなの前でこんな姿を晒すなんて……な、なんて不敬な……！","ENG":"How blasphemous of you... to make me appear like this in front of everyone...!","TWN":"竟然在大家面前讓我出醜……你、你怎麼能這麼無禮……！"},"stage":{"bg":"CHOCOLAT_01","slots":{"L":null,"C":null,"R":{"char_id":"BIBLIDES_XMAS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"CAKE_CHOCOLAT_NPC_BROTHER","text":{"KOREA":"후후후, 미안하지만 그렇게는 안 된다네, 시스터.","JPN":"ふふふ、悪いがそれはできないぞ、シスター。","ENG":"Hahaha. I'm sorry, but I cannot give back your glasses, Sister.","TWN":"嘿嘿嘿，很抱歉，但這是不可能的，修女。"},"stage":{"bg":"CHOCOLAT_01","slots":{"L":null,"C":null,"R":{"char_id":"BIBLIDES_XMAS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"CAKE_CHOCOLAT_NPC_BROTHER","text":{"KOREA":"원래 도도한 안경 시스터의 매력은 안경을 벗었을 때 비로소 꽃피는 법이거든.","JPN":"もともと高慢な眼鏡シスターの魅力は、眼鏡を外してこそ開花するものなのだ。","ENG":"For only the charm of the arrogant Sister with glasses blooms when she takes them off.","TWN":"原本高傲的眼鏡修女，只有在摘下眼鏡時才會綻放自己的魅力。"},"stage":{"bg":"CHOCOLAT_01","slots":{"L":null,"C":null,"R":{"char_id":"BIBLIDES_XMAS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"CAKE_CHOCOLAT_NPC_BROTHER","text":{"KOREA":"안경이란 결국 임팩트를 주기 위한 구속구에 불과하지.","JPN":"眼鏡とは結局、インパクトを与えるための拘束具に過ぎない。","ENG":"Glasses are merely restraints used to make an impact.","TWN":"眼鏡終究只是用來給人留下印象的裝飾品而已。"},"stage":{"bg":"CHOCOLAT_01","slots":{"L":null,"C":null,"R":{"char_id":"BIBLIDES_XMAS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"BIBLIDES_XMAS_NULL_NULL","text":{"KOREA":"무, 무슨… 그런 영문 모를 소리를……!","JPN":"な、何を……わけのわからないことを……！","ENG":"W-what...? This is nonsense...!","TWN":"什、什麼……怎麼又說些莫名其妙的話……！"},"stage":{"bg":"CHOCOLAT_01","slots":{"L":null,"C":null,"R":{"char_id":"BIBLIDES_XMAS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"CLOUDIA_XMAS_NULL_NULL","text":{"KOREA":"저, 쇼콜라 형제님…….","JPN":"あの、ブラザー・ショコラ……","ENG":"Uh, Brother Chocolat...?","TWN":"讓我來吧……"},"stage":{"bg":"CHOCOLAT_01","slots":{"L":{"char_id":"CLOUDIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIBLIDES_XMAS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"CLOUDIA_XMAS_NULL_NULL","text":{"KOREA":"루체 자매님은 아무런 잘못도 없어요.","JPN":"シスター・ルーチェは何も悪くありません。","ENG":"Sister Luce did nothing wrong.","TWN":"露契姊妹沒有錯。"},"stage":{"bg":"CHOCOLAT_01","slots":{"L":{"char_id":"CLOUDIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIBLIDES_XMAS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"CLOUDIA_XMAS_NULL_NULL","text":{"KOREA":"제가 대신 산타걸이 될 게요… 그러니까 이제 그만 자매님의 안경을 돌려주세요…….","JPN":"私が代わりにサンタガールになります……ですから、もうシスター・ルーチェの眼鏡を返してください……","ENG":"I'll wear the Santa suit instead... So please give her back her glasses...","TWN":"我來當聖誕女孩吧……所以請把露契姊妹的眼鏡還給她……"},"stage":{"bg":"CHOCOLAT_01","slots":{"L":{"char_id":"CLOUDIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIBLIDES_XMAS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"CAKE_CHOCOLAT_NPC_BROTHER","text":{"KOREA":"오호호호~! 참으로 갸륵한 마음의 시스터로군.","JPN":"オホホホ～！　なんと健気なシスターなんだ。","ENG":"Hohohoho! What a noble heart you have!","TWN":"喔呵呵呵～！真是個心地善良的修女啊。"},"stage":{"bg":"CHOCOLAT_01","slots":{"L":{"char_id":"CLOUDIA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BIBLIDES_XMAS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"CAKE_CHOCOLAT_NPC_BROTHER","text":{"KOREA":"하지만 아직 때가 아니라네.","JPN":"だが、まだダメだ。","ENG":"However, now is not the right time.","TWN":"但現在還不是時候。"},"stage":{"bg":"CHOCOLAT_01","slots":{"L":{"char_id":"CLOUDIA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BIBLIDES_XMAS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"CLOUDIA_XMAS_NULL_NULL","text":{"KOREA":"때가… 아니라고요……?","JPN":"まだ……？","ENG":"Not... the right time...?","TWN":"不是時候……？"},"stage":{"bg":"CHOCOLAT_01","slots":{"L":{"char_id":"CLOUDIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIBLIDES_XMAS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"CAKE_CHOCOLAT_NPC_BROTHER","text":{"KOREA":"자네가 소원을 빌지 않았나?","JPN":"君が願っただろう？","ENG":"You made a wish, didn't you?","TWN":"你不是許了願嗎？"},"stage":{"bg":"CHOCOLAT_01","slots":{"L":{"char_id":"CLOUDIA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BIBLIDES_XMAS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"CAKE_CHOCOLAT_NPC_BROTHER","text":{"KOREA":"오늘 밤, 두 시스터의 사이가 가까워질 바란다고.","JPN":"今夜、2人のシスターが仲良くなりますようにと。","ENG":"You wished that tonight, the two Sisters would become closer.","TWN":"希望今晚兩位姊妹的關係能更親近一些。"},"stage":{"bg":"CHOCOLAT_01","slots":{"L":{"char_id":"CLOUDIA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BIBLIDES_XMAS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"CAKE_CHOCOLAT_NPC_BROTHER","text":{"KOREA":"사람과 사람이 가까워지려면 몇번의 기적이 겹치고 겹쳐야 가능한 법이거든.","JPN":"人と人が絆を深めるためには、奇跡が何度も重ならなくてはいけないのだ。","ENG":"In order to make two people become closer, miracles must occur over and over again.","TWN":"人與人之間要想親近，需要幾次奇蹟重疊起來才有可能。"},"stage":{"bg":"CHOCOLAT_01","slots":{"L":{"char_id":"CLOUDIA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BIBLIDES_XMAS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"CLOUDIA_XMAS_NULL_NULL","text":{"KOREA":"그, 그렇다면 설마……?","JPN":"じゃ、じゃあまさか……？","ENG":"Th-then...?","TWN":"你說什麼？難道……？"},"stage":{"bg":"CHOCOLAT_01","slots":{"L":{"char_id":"CLOUDIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BIBLIDES_XMAS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"subtitle","speaker":null,"text":{"KOREA":"같은 시간","JPN":"そのころ","ENG":"Meanwhile","TWN":"同一時間","SCN":"同一时间","DEU":"Meanwhile","FRA":"Meanwhile"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"CLOUDIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIBLIDES_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>성황청</color> 성 요한 대성당","JPN":"<color=#ffd34c>聖皇庁</color>聖ヨハン大聖堂","ENG":"<color=#ffd34c>Holy Curia</color> St. Johan Cathedral","TWN":"<color=#ffd34c>聖皇廳</color> 聖約翰大教堂","SCN":"<color=#ffd34c>圣廷</color> 圣约翰大教堂","DEU":"<color=#ffd34c>Holy Curia</color> St. Johan Cathedral","FRA":"<color=#ffd34c>Holy Curia</color> St. Johan Cathedral"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"CLOUDIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIBLIDES_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"뭐야? 넬슨도 안경도… 아무도 마중 안 나왔잖아?","JPN":"なんだ？　ネルソンも眼鏡も……誰も迎えに来てないじゃん。","ENG":"What the heck? Nelson and Specky... didn't come to pick me up?","TWN":"什麼？尼爾森和四眼姊姊……沒一個人來接我嗎？"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"치이, 너무해. 나만 혼자 내버려두다니… 기껏 깜짝 놀라게 해주려고 준비했는데…….","JPN":"ちいっ、ひどい。アタシをひとりにするなんて……思いっきりびっくりさせてあげようと思ったのに……","ENG":"Tch. I can't believe they did this to me... I was going to surprise them...","TWN":"哎呀，太過分了。竟然把我一個人丟下……我還特意準備了驚喜呢……"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};